#[test]
fn source_lines_counts_correctly() {
    let fi = make_fi(3, 7, vec![]);
    assert_eq!(source_lines(&fi), 5);
}

#[test]
fn source_lines_single_line() {
    let fi = make_fi(5, 5, vec![]);
    assert_eq!(source_lines(&fi), 1);
}

