use crate::runtime::{Example, StepResult};
use std::cell::RefCell;
use std::path::Path;

thread_local! {
    pub static FIXTURE_DIR: RefCell<Option<tempfile::TempDir>> = const { RefCell::new(None) };
    pub static FIXTURE_ROOT: RefCell<Option<String>> = const { RefCell::new(None) };
}

pub fn fixture_root() -> Option<String> {
    FIXTURE_ROOT.with(|r| r.borrow().clone())
}

pub fn ensure_fixture_dir() -> Result<String, StepResult> {
    FIXTURE_DIR.with(|dir| {
        let mut borrow = dir.borrow_mut();
        if borrow.is_none() {
            match tempfile::TempDir::new() {
                Ok(td) => {
                    let path = td.path().to_string_lossy().to_string();
                    *borrow = Some(td);
                    FIXTURE_ROOT.with(|r| *r.borrow_mut() = Some(path));
                }
                Err(e) => {
                    return Err(StepResult::fail(format!("failed to create temp dir: {}", e)));
                }
            }
        }
        Ok(FIXTURE_ROOT.with(|r| r.borrow().clone().unwrap()))
    })
}

pub fn write_fixture(root: &str, relative: &str, content: &str) -> Result<(), StepResult> {
    let full = Path::new(root).join(relative);
    if let Some(parent) = full.parent() {
        std::fs::create_dir_all(parent)
            .map_err(|e| StepResult::fail(format!("mkdir {}: {}", parent.display(), e)))?;
    }
    std::fs::write(&full, content)
        .map_err(|e| StepResult::fail(format!("write {}: {}", full.display(), e)))?;
    Ok(())
}

pub fn accumulate_sum_source(params: &str) -> String {
    let ids: Vec<&str> = params.split(',').collect();
    let (p0, p1, p2) = if ids.len() >= 3 {
        (ids[0].trim(), ids[1].trim(), ids[2].trim())
    } else {
        ("a", "b", "sum")
    };
    format!(
        "pub fn accumulate_sum({p0}: i32, {p1}: i32) -> i32 {{\n    let {p2} = {p0} + {p1};\n    let extra = {p2} * 2;\n    let more = extra + {p0};\n    let result = more + {p1};\n    result\n}}\n",
        p0 = p0, p1 = p1, p2 = p2
    )
}

pub fn resolve_params(step_text: &str, example: &Example) -> String {
    let mut result = step_text.to_string();
    for (k, v) in example {
        result = result.replace(&format!("<{}>", k), v);
    }
    result
}

pub fn step_then_exit_code(step: &str, world: &mut crate::runtime::World) -> Option<StepResult> {
    static RE: std::sync::OnceLock<regex::Regex> = std::sync::OnceLock::new();
    let re = RE.get_or_init(|| regex::Regex::new(r#"^the exit code is "?(\d+)"?$"#).unwrap());
    let caps = re.captures(step)?;
    let expected: i32 = caps.get(1).unwrap().as_str().parse().unwrap();
    let actual = match world.exit_code {
        Some(c) => c,
        None => return Some(StepResult::fail("exit code not yet recorded")),
    };
    Some(if actual == expected {
        StepResult::ok()
    } else {
        let stderr = world.stderr.as_deref().unwrap_or("");
        let stdout = world.stdout.as_deref().unwrap_or("");
        StepResult::fail(format!(
            "expected exit code {}, got {}\nstdout: {}\nstderr: {}",
            expected, actual, stdout, stderr
        ))
    })
}

pub fn step_then_stdout_reports_pair_for(step: &str, world: &mut crate::runtime::World) -> Option<StepResult> {
    static RE: std::sync::OnceLock<regex::Regex> = std::sync::OnceLock::new();
    let re = RE.get_or_init(|| {
        regex::Regex::new(r#"^stdout reports a duplicate pair for "([^"]+)" and "([^"]+)"$"#)
            .unwrap()
    });
    let caps = re.captures(step)?;
    let left_file = caps.get(1).unwrap().as_str();
    let right_file = caps.get(2).unwrap().as_str();

    let stdout = match &world.stdout {
        Some(s) => s.clone(),
        None => return Some(StepResult::fail("stdout not yet recorded")),
    };

    let left_name = Path::new(left_file)
        .file_name()
        .and_then(|n| n.to_str())
        .unwrap_or(left_file);
    let right_name = Path::new(right_file)
        .file_name()
        .and_then(|n| n.to_str())
        .unwrap_or(right_file);

    Some(
        if stdout.contains(left_name) && stdout.contains(right_name) && stdout.contains("DUPLICATE")
        {
            StepResult::ok()
        } else {
            StepResult::fail(format!(
                "expected stdout to report pair for {} and {}, got: {}",
                left_file, right_file, stdout
            ))
        },
    )
}

pub fn step_then_no_duplicate_pair(step: &str, world: &mut crate::runtime::World) -> Option<StepResult> {
    if step != "no duplicate pair is reported" {
        return None;
    }
    let stdout = match &world.stdout {
        Some(s) => s.clone(),
        None => return Some(StepResult::fail("stdout not yet recorded")),
    };
    Some(if !stdout.contains("DUPLICATE") {
        StepResult::ok()
    } else {
        StepResult::fail(format!("expected no duplicate pair, stdout: {}", stdout))
    })
}

// Options that take a value argument (not a path)
const VALUE_OPTIONS: &[&str] = &[
    "--threshold",
    "--min-lines",
    "--min-nodes",
    "--format",
    "--lang",
    "--exclude",
];

pub fn resolve_arg_paths(args_str: &str) -> Vec<String> {
    let root = fixture_root();
    let tokens: Vec<&str> = args_str.split_whitespace().collect();
    let mut result = Vec::new();
    let mut skip_next = false;
    for tok in tokens.iter() {
        if skip_next {
            skip_next = false;
            result.push(tok.to_string());
            continue;
        }
        if tok.starts_with("--") || tok.starts_with('-') {
            if VALUE_OPTIONS.contains(tok) {
                skip_next = true;
            }
            result.push(tok.to_string());
        } else if let Some(ref r) = root {
            let p = Path::new(tok);
            if p.is_absolute() {
                result.push(tok.to_string());
            } else {
                result.push(Path::new(r).join(tok).to_string_lossy().to_string());
            }
        } else {
            result.push(tok.to_string());
        }
    }
    result
}

use drywall::scan::{
    build_glob_set, is_builtin_excluded, is_rust_file, should_scan_file, should_skip,
};
use proptest::prelude::*;
use std::path::Path;

const BUILTIN_DIRS: &[&str] = &[
    ".git",
    "target",
    "node_modules",
    "__pycache__",
    "vendor",
    "dist",
    ".next",
];

fn builtin_dir() -> impl Strategy<Value = &'static str> {
    proptest::sample::select(BUILTIN_DIRS)
}

fn safe_segment() -> impl Strategy<Value = String> {
    "[a-z][a-z0-9_]{0,8}".prop_map(|s| s)
}

proptest! {
    // --- is_builtin_excluded invariants ---

    #[test]
    fn builtin_excluded_any_segment_position(
        prefix in prop::collection::vec(safe_segment(), 0..3),
        excluded in builtin_dir(),
        suffix in prop::collection::vec(safe_segment(), 0..3),
    ) {
        let mut parts = prefix;
        parts.push(excluded.to_string());
        parts.extend(suffix);
        parts.push("file.rs".to_string());
        let path = parts.join("/");
        prop_assert!(
            is_builtin_excluded(Path::new(&path)),
            "expected excluded for path: {}",
            path
        );
    }

    #[test]
    fn non_builtin_segments_not_excluded(
        segments in prop::collection::vec(safe_segment(), 1..4),
    ) {
        let mut path_parts = segments.clone();
        path_parts.push("file.rs".to_string());
        let path = path_parts.join("/");
        // Only paths with no builtin segment should pass
        let has_builtin = segments.iter().any(|s| BUILTIN_DIRS.contains(&s.as_str()));
        if !has_builtin {
            prop_assert!(
                !is_builtin_excluded(Path::new(&path)),
                "expected non-excluded for path: {}",
                path
            );
        }
    }

    #[test]
    fn partial_name_match_not_excluded(
        excluded in builtin_dir(),
        suffix in "[a-z]{1,4}",
    ) {
        let segment = format!("{}{}", excluded, suffix);
        let path = format!("{}/file.rs", segment);
        prop_assert!(
            !is_builtin_excluded(Path::new(&path)),
            "partial name '{}' must not be excluded",
            segment
        );
    }

    // --- is_rust_file invariant ---

    #[test]
    fn is_rust_file_iff_rs_extension(
        stem in "[a-z][a-z0-9_]{0,10}",
        ext in "[a-z]{1,4}",
    ) {
        let path = format!("{}.{}", stem, ext);
        let result = is_rust_file(Path::new(&path));
        if ext == "rs" {
            prop_assert!(result, "expected .rs file to be rust: {}", path);
        } else {
            prop_assert!(!result, "expected non-.rs file to not be rust: {}", path);
        }
    }

    // --- should_skip (glob) invariants ---

    #[test]
    fn should_skip_empty_set_never_skips(path in "[a-z/]{1,20}\\.rs") {
        let gs = build_glob_set(&[]).unwrap();
        prop_assert!(!should_skip(Path::new(&path), &gs));
    }

    #[test]
    fn should_skip_matching_pattern_skips(stem in "[a-z][a-z0-9_]{0,8}") {
        let path = format!("acceptance/{}.rs", stem);
        let gs = build_glob_set(&["acceptance/**".to_string()]).unwrap();
        prop_assert!(
            should_skip(Path::new(&path), &gs),
            "expected acceptance path to be skipped: {}",
            path
        );
    }

    #[test]
    fn should_skip_non_matching_path_not_skipped(stem in "[a-z][a-z0-9_]{0,8}") {
        let path = format!("src/{}.rs", stem);
        let gs = build_glob_set(&["acceptance/**".to_string()]).unwrap();
        prop_assert!(
            !should_skip(Path::new(&path), &gs),
            "expected src path not to be skipped: {}",
            path
        );
    }

    #[test]
    fn glob_union_order_independent(
        stem in "[a-z][a-z0-9_]{0,8}",
    ) {
        let p1 = "acceptance/**".to_string();
        let p2 = format!("tests/{}.rs", stem);
        let path = format!("tests/{}.rs", stem);

        let gs_ab = build_glob_set(&[p1.clone(), p2.clone()]).unwrap();
        let gs_ba = build_glob_set(&[p2.clone(), p1.clone()]).unwrap();

        let result_ab = should_skip(Path::new(&path), &gs_ab);
        let result_ba = should_skip(Path::new(&path), &gs_ba);

        prop_assert_eq!(
            result_ab, result_ba,
            "glob union must be order-independent for path: {}",
            path
        );
    }

    #[test]
    fn glob_union_idempotent(stem in "[a-z][a-z0-9_]{0,8}") {
        let pattern = format!("tests/{}.rs", stem);
        let path = format!("tests/{}.rs", stem);

        let gs_once = build_glob_set(&[pattern.clone()]).unwrap();
        let gs_twice = build_glob_set(&[pattern.clone(), pattern.clone()]).unwrap();

        let result_once = should_skip(Path::new(&path), &gs_once);
        let result_twice = should_skip(Path::new(&path), &gs_twice);

        prop_assert_eq!(
            result_once, result_twice,
            "duplicating a glob pattern must not change skip result for: {}",
            path
        );
    }

    // --- should_scan_file composition invariants ---

    #[test]
    fn should_scan_file_non_rs_never_scanned(
        stem in "[a-z][a-z0-9_]{0,8}",
        ext in "[a-z]{1,4}",
    ) {
        // Non-.rs files must never be scanned regardless of git-ignore oracle
        prop_assume!(ext != "rs");
        let path = format!("src/{}.{}", stem, ext);
        let gs = build_glob_set(&[]).unwrap();
        prop_assert!(!should_scan_file(Path::new(&path), &gs, &|_| false));
        prop_assert!(!should_scan_file(Path::new(&path), &gs, &|_| true));
    }

    #[test]
    fn should_scan_file_builtin_excluded_never_scanned(
        excluded in proptest::sample::select(BUILTIN_DIRS),
        stem in "[a-z][a-z0-9_]{0,8}",
    ) {
        let path = format!("{}/{}.rs", excluded, stem);
        let gs = build_glob_set(&[]).unwrap();
        prop_assert!(
            !should_scan_file(Path::new(&path), &gs, &|_| false),
            "builtin-excluded path must not scan: {}",
            path
        );
    }

    #[test]
    fn should_scan_file_git_ignored_never_scanned(stem in "[a-z][a-z0-9_]{0,8}") {
        let path = format!("src/{}.rs", stem);
        let gs = build_glob_set(&[]).unwrap();
        prop_assert!(
            !should_scan_file(Path::new(&path), &gs, &|_| true),
            "git-ignored file must not scan: {}",
            path
        );
    }

    #[test]
    fn should_scan_file_glob_excluded_never_scanned(stem in "[a-z][a-z0-9_]{0,8}") {
        let path = format!("acceptance/{}.rs", stem);
        let gs = build_glob_set(&["acceptance/**".to_string()]).unwrap();
        prop_assert!(
            !should_scan_file(Path::new(&path), &gs, &|_| false),
            "glob-excluded file must not scan: {}",
            path
        );
    }

    #[test]
    fn should_scan_file_clean_rs_path_scanned(stem in "[a-z][a-z0-9_]{0,8}") {
        // A .rs file in src/ with no exclusions and not git-ignored must scan
        let path = format!("src/{}.rs", stem);
        let gs = build_glob_set(&[]).unwrap();
        prop_assert!(
            should_scan_file(Path::new(&path), &gs, &|_| false),
            "clean .rs file must scan: {}",
            path
        );
    }
}

